INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000000', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'text', '{"html":"<h3>What construction surveying is</h3><p><strong>Construction surveying</strong> (also called <em>stakeout</em>, <em>layout</em>, or <em>setting out</em>) is the process of transferring the geometry of an engineering design from the plans onto the ground so that contractors can build to the correct horizontal position and elevation. Where a <strong>boundary survey</strong> recovers existing property lines and a <strong>topographic survey</strong> records existing ground, construction surveying does the opposite job: it <em>places</em> points, lines, and grades that do not yet exist, marking where structures, pavements, utilities, and earthwork must go.</p><p>The construction surveyor works from approved plans, a coordinate system, and a network of <strong>control</strong>. He computes the coordinates and elevations of points to be staked, sets stakes (or robotic/GNSS layout points) in the field, and provides the contractor with the information needed to build &mdash; line, offset, cut or fill, and grade. Accuracy requirements are often tighter than a routine boundary survey: a misplaced anchor bolt or a sewer invert a tenth of a foot off can be very costly to fix once concrete is poured.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000001', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'text', '{"html":"<h3>Offset stakes and why we offset</h3><p>A stake set directly <em>on</em> a finished line or corner would be destroyed the moment the excavator arrives. Construction surveyors therefore set <strong>offset stakes</strong>: stakes placed a known, even horizontal distance to the side of the actual line (for example, 5 ft, 10 ft, or 25 ft offset), clear of construction activity, from which the contractor can re-establish the true line at any time. The stake is marked with the <strong>offset distance and direction</strong> (e.g., &lsquo;10&prime; OFFSET&rsquo; to centerline) and, for grading, with the <strong>cut or fill</strong> from the top of the stake (or from existing ground) to the design surface.</p><p>Common construction stakes include the <strong>slope stake</strong> (set at the theoretical intersection of the design slope with natural ground, marking the limit of grading and the cut/fill there), the <strong>grade stake</strong> (gives elevation/grade information), the <strong>offset hub</strong> (a precise point off line), and the <strong>blue top</strong> (a stake driven so its top is exactly at finished subgrade elevation). Markings follow standard conventions &mdash; station, offset, and cut (C) or fill (F) &mdash; so any crew member can read them.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000002', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'table', '{"headers":["Stake type","What it gives the contractor","Typical marking"],"rows":[["Offset hub / line stake","Horizontal line or point, set off the work","Station + offset distance & direction"],["Slope stake","Limit of grading (catch point) + cut/fill there","C or F + slope ratio + offset to hinge"],["Grade / cut stake","Vertical info: cut or fill to design grade","C 2.4 (cut) or F 1.1 (fill)"],["Blue top","Top of stake set exactly at finished subgrade","(top is the grade — no cut/fill)"],["Reference / control point","Permanent horizontal & vertical control","Point name, N/E, elevation"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000003', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'text', '{"html":"<h3>Cut, fill, and grade</h3><p>The two governing quantities in construction layout are <strong>cut</strong> and <strong>fill</strong>. A <strong>cut</strong> means the design (finished) elevation is <em>below</em> existing ground, so material must be excavated; a <strong>fill</strong> means the design elevation is <em>above</em> existing ground, so material must be added. The signed relationship is simply <em>cut/fill = design elevation &minus; ground elevation</em>: a negative result is a cut, a positive result is a fill (sign conventions vary by office, so always confirm). On a stake the surveyor writes the magnitude with the letter, e.g. &lsquo;C 1.8&rsquo; (cut 1.8 ft) or &lsquo;F 0.6&rsquo; (fill 0.6 ft), so the operator knows how much to dig or build up at that point.</p><p><strong>Grade</strong> (or <strong>slope</strong>) expresses how the design surface rises or falls along a line, usually as a <strong>percent grade</strong>: percent grade = (rise &divide; horizontal run) &times; 100. A +2.00% grade rises 2 ft per 100 ft. The surveyor uses grade to compute the design elevation at any station along a line and then derives the cut or fill against the ground at that point.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000004', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'equation', '{"latex":"\\text{cut/fill} = \\text{Elev}_{design} - \\text{Elev}_{ground}","label":"Cut/fill at a stake (negative = cut, positive = fill)","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000005', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'callout', '{"type":"info","text":"Layout discipline: always stake from established control, never from a previously set construction stake. Stakes get bumped, frost-heaved, and knocked out of grade. Carrying line and grade stake-to-stake propagates error across the whole project."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000006', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: An offset stake clear of the excavation, marked with station, offset distance, and cut to the design grade."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0001-0000-0000-000000000007', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'key_takeaways', '{"title":"Key Takeaways","items":["Construction surveying lays out the design on the ground; it builds geometry rather than recording it.","Offset stakes are set a known distance off the line so they survive construction.","Cut means excavate (design below ground); fill means add material (design above ground).","cut/fill = design elevation − ground elevation; percent grade = rise ÷ run × 100.","Always stake from control, never from a previously set stake."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000000', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'text', '{"html":"<h3>From control to building lines</h3><p>Building layout begins by establishing <strong>horizontal control</strong> &mdash; at least two intervisible, well-monumented points of known coordinates near the site &mdash; and a <strong>baseline</strong> from which the structure is dimensioned. Modern practice computes the coordinates of every building corner and primary line from the plan dimensions and the site coordinate system, then stakes those corners directly with a total station or GNSS rover. The corners define the <strong>building lines</strong> (usually the outside face of foundation or the column gridlines). Before any dirt moves, the surveyor verifies the layout: the overall dimensions, the squareness of corners, and the agreement of the two diagonals of each rectangular figure.</p><p>Two field checks are classic and still indispensable. The <strong>3-4-5 rule</strong> (a right triangle with sides in the ratio 3:4:5, or any multiple) proves a corner is square. Comparing the two <strong>diagonals</strong> of a rectangle is even faster: in a true rectangle the diagonals are equal, so any difference reveals a layout error before construction locks it in.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000001', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'equation', '{"latex":"d = \\sqrt{L^2 + W^2}","label":"Diagonal of a rectangular building (L × W) — diagonals must be equal","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000002', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'text', '{"html":"<h3>Batter boards and offset hubs</h3><p>The corner stakes that define a building are destroyed the moment excavation for the footings begins, so the surveyor preserves line and grade with <strong>batter boards</strong>. A batter board is a horizontal board nailed between two posts set a convenient offset (commonly 3&ndash;5 ft) outside each building corner. A nail or saw-kerf in the board marks the exact <strong>building line</strong>, and strings stretched between opposing batter boards re-create the wall lines over the open excavation at any time. The top of the board is frequently set to a known elevation (e.g., top of footing or finished floor), so the strings give <em>grade</em> as well as line.</p><p>Because the batter boards sit outside the work, the contractor can drop a plumb bob from a string intersection to find a corner, check footing width, and confirm grade without re-surveying. The surveyor also sets durable <strong>offset hubs</strong> &mdash; reference points a known offset off each principal line &mdash; from which line can be re-run if a batter board is disturbed. The key principle is redundancy: line and grade are preserved on multiple stable references outside the construction zone.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000003', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'table', '{"headers":["Layout element","Purpose","Field check"],"rows":[["Baseline / control pair","Origin & orientation for all dimensions","Inverse between points vs. record"],["Corner stakes (coordinates)","Define building lines & footprint","3-4-5 squareness; diagonals equal"],["Batter boards","Preserve line & grade across excavation","String intersections plumb to corners"],["Offset hubs","Re-establish line if boards disturbed","Re-inverse from control"],["Site benchmark","Vertical datum for floor/footing elevations","Level loop closes back to source BM"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000004', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'text', '{"html":"<h3>Transferring the vertical datum</h3><p>Every elevation on the site &mdash; finished floor, top of footing, slab, subgrade &mdash; must tie to a single, reliable <strong>vertical datum</strong>. The surveyor runs a level loop from a published or project <strong>benchmark</strong> (BM) of known elevation to a stable <strong>site benchmark</strong> set in a protected location, and <em>closes the loop back to the source</em> to prove the transfer. The site BM then anchors the height of instrument (HI) used to set grade stakes, blue tops, and batter-board elevations. The <strong>finished-floor elevation (FFE)</strong> stated on the plans is the controlling datum for the structure; footing and slab elevations are derived from it. A blown vertical transfer puts the entire building at the wrong height, so the closure check is not optional.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000005', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'callout', '{"type":"info","text":"Check before you build: equal diagonals on a rectangle catch a racked (out-of-square) layout instantly. A difference of even a few hundredths between diagonals usually means a corner coordinate or a held distance is wrong — find it before footings are poured."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000006', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Batter boards offset outside each corner; strings between them re-create building lines and grade over the open excavation."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0002-0000-0000-000000000007', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'key_takeaways', '{"title":"Key Takeaways","items":["Lay out from control and a baseline; compute corners by coordinates from plan dimensions.","Prove squareness with 3-4-5 and verify rectangles by comparing equal diagonals.","Batter boards and offset hubs preserve line and grade once corner stakes are excavated.","Transfer the vertical datum from a benchmark and close the level loop to prove it.","Finished-floor elevation is the controlling vertical datum for the structure."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000000', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'text', '{"html":"<h3>Anatomy of a horizontal curve</h3><p>Roads change direction through <strong>horizontal curves</strong>. The simplest is the <strong>simple (circular) curve</strong>, a single arc of radius <em>R</em> joining two straight tangents. Where the two tangents would meet is the <strong>PI</strong> (point of intersection); the angle between the tangents (equal to the curve&rsquo;s central angle) is the <strong>intersection / deflection angle I</strong> (often written &Delta;). The curve begins at the <strong>PC</strong> (point of curvature, where the back tangent leaves the straight line) and ends at the <strong>PT</strong> (point of tangency, where the forward tangent resumes). The straight-line distance from PC to PI (equal to PI to PT) is the <strong>tangent length T</strong>; the distance along the arc from PC to PT is the <strong>curve (arc) length L</strong>.</p><p>The whole geometry follows from just two inputs &mdash; the radius <em>R</em> and the central angle <em>I</em>. From those, the surveyor computes T, L, the external and middle-ordinate distances, and the station of the PC and PT, then lays the curve out on the ground.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000001', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'equation', '{"latex":"T = R\\,\\tan\\!\\left(\\frac{I}{2}\\right)","label":"Tangent length of a simple curve","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000002', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'equation', '{"latex":"L = R\\,I_{rad} = \\frac{\\pi R I}{180}\\quad(I \\text{ in degrees})","label":"Arc length of a simple curve","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000003', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'text', '{"html":"<h3>Degree of curve</h3><p>Highway designers traditionally describe curve sharpness by <strong>degree of curve</strong> rather than radius. Under the <strong>arc definition</strong> (standard for highways), the degree of curve <em>D<sub>a</sub></em> is the central angle subtended by a <strong>100-ft arc</strong>. Because a full circle (360&deg;) corresponds to a circumference of 2&pi;R, a 100-ft arc subtends D<sub>a</sub> = (100 / 2&pi;R) &times; 360 = <strong>5729.58 / R</strong> degrees. A larger degree of curve means a <em>sharper</em>, smaller-radius curve; a 1&deg; curve has R &asymp; 5729.58 ft, while a 6&deg; curve has R &asymp; 954.9 ft. (Railroads often use the <strong>chord definition</strong>, where the 100 ft is a chord rather than an arc; the two differ slightly and must not be mixed.)</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000004', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'equation', '{"latex":"D_a = \\frac{5729.58}{R}","label":"Degree of curve — arc definition (deg per 100-ft arc)","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000005', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'text', '{"html":"<h3>Staking a curve by deflection angles</h3><p>The standard field method to set a circular curve is the <strong>deflection-angle method</strong> from the PC. A fundamental property of a circle is that the deflection angle from the tangent at the PC to any point on the curve equals <em>half</em> the central angle subtended by the arc to that point. So the total deflection from the back tangent to the PT is exactly <strong>I/2</strong>. The surveyor occupies the PC, backsights along the back tangent, and turns incremental deflection angles to set the curve at regular stations (e.g., full or half stations), measuring the corresponding chord to each point. Summing the increments must close on I/2 at the PT &mdash; a built-in check on the layout.</p><p>The deflection per station is proportional to the arc to that station: for an arc length &ell;, the deflection is (&ell; / L) &times; (I/2), or equivalently a constant rate per foot of arc. Coordinate-based stakeout with a total station or GNSS has largely automated the arithmetic, but the deflection geometry remains the conceptual backbone and the field check.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000006', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'text', '{"html":"<h3>Vertical curves</h3><p>Where two different grades (tangent slopes) meet in profile, they are joined by a <strong>vertical curve</strong> &mdash; an <strong>equal-tangent parabola</strong>, used because it produces a constant rate of grade change and a smooth ride. A <strong>crest</strong> vertical curve joins a rising grade to a falling one (a hilltop); a <strong>sag</strong> vertical curve joins a falling grade to a rising one (a valley). The curve is defined by its length <em>L</em> and the two grades <em>g<sub>1</sub></em> and <em>g<sub>2</sub></em> (in percent). Elevations along the parabola are computed from the elevation of the <strong>BVC</strong> (beginning of vertical curve) plus the tangent-grade term and a parabolic offset that varies with the square of the distance from the BVC. Along a straight (tangent) grade, the elevation at any point is simply <strong>design elevation = start elevation + grade% &times; distance &divide; 100</strong>.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000007', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'equation', '{"latex":"\\text{Elev} = \\text{Elev}_{start} + \\frac{g\\% \\cdot d}{100}","label":"Profile-grade elevation along a tangent (g in percent, d in feet)","display":"block"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000008', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'callout', '{"type":"warning","text":"Do not mix curve definitions or angle units. Arc definition (highways) and chord definition (railroads) give different radii for the same degree of curve. And L = R·I requires I in RADIANS — use L = πRI/180 when I is in degrees."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000009', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'table', '{"headers":["Element","Symbol","Relationship"],"rows":[["Radius","R","Given (or R = 5729.58 / Da)"],["Intersection / central angle","I (Δ)","Measured between tangents"],["Tangent length","T","T = R·tan(I/2)"],["Arc (curve) length","L","L = R·I (rad) = πRI/180 (deg)"],["Degree of curve (arc)","Da","Da = 5729.58 / R"],["Total deflection PC→PT","—","I/2"]]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000010', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Simple horizontal curve geometry — PC, PI, PT with radius R, central angle I, tangent T, and arc length L."}'::jsonb, 10);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0003-0000-0000-000000000011', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'key_takeaways', '{"title":"Key Takeaways","items":["A simple curve is set by R and I; the curve runs PC → PT through the PI.","T = R·tan(I/2); arc length L = R·I (radians) = πRI/180 (degrees).","Degree of curve (arc) Da = 5729.58/R; bigger Da = sharper, smaller-radius curve.","Stake curves by deflection angles from the PC; total deflection to the PT is I/2.","Vertical curves are equal-tangent parabolas; on a tangent, elev = start + grade%·d/100."]}'::jsonb, 11);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000000', '1682393e-399c-419e-93a7-1b373316c483', 'text', '{"html":"<h3>Laying out a pipeline</h3><p>Utility stakeout sets out the <strong>horizontal alignment</strong> of a pipe, conduit, or duct bank and the <strong>vertical grade</strong> it must follow. As with roads, the surveyor works from control and stakes <strong>offset</strong> from the trench centerline (so the stakes survive trenching), marking each stake with the <strong>station</strong>, the <strong>offset</strong>, and the <strong>cut</strong> from the reference point down to the pipe. For gravity systems the controlling elevation is the <strong>invert</strong> &mdash; the inside bottom of the pipe &mdash; because flow depth and slope are measured from the invert, not the crown (top) or the centerline. Stakes therefore typically give &lsquo;cut to invert.&rsquo;</p><p>Manholes, inlets, cleanouts, and service connections are staked as discrete points with their own invert and rim elevations. The surveyor verifies the design before staking: that inverts fall continuously downstream, that the slope meets the minimum for self-cleaning velocity, and that the pipe clears existing crossing utilities.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000001', '1682393e-399c-419e-93a7-1b373316c483', 'text', '{"html":"<h3>Gravity grade and invert elevations</h3><p>A gravity pipeline flows because its invert <strong>falls</strong> continuously from upstream to downstream at a designed <strong>slope</strong> (e.g., a sanitary sewer at 0.40%, meaning the invert drops 0.40 ft per 100 ft). The invert elevation at any downstream station is the upstream (starting) invert minus the slope times the distance: <em>Inv = Inv<sub>start</sub> &minus; (slope% &times; distance &divide; 100)</em>. Because the downstream direction <em>falls</em>, the slope term is subtracted. Designers also specify a <strong>minimum slope</strong> so the flow keeps a self-cleaning velocity and a <strong>maximum slope</strong> so it does not scour; the surveyor stakes to the design inverts so the contractor lays pipe to the right fall.</p><p>The <strong>cut</strong> the operator needs at a station is the ground elevation there minus the invert elevation (plus the pipe wall and bedding, per the detail). Deep sewers in particular demand careful, frequent grade staking &mdash; a laser or a string line on grade boards is set from the surveyor&rsquo;s stakes &mdash; because a reversed or flat invert in a gravity line is a serious, expensive defect.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000002', '1682393e-399c-419e-93a7-1b373316c483', 'equation', '{"latex":"\\text{Inv} = \\text{Inv}_{start} - \\frac{s\\% \\cdot d}{100}","label":"Downstream pipe invert at distance d (s = slope in percent, fall positive downstream)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000003', '1682393e-399c-419e-93a7-1b373316c483', 'table', '{"headers":["Term","Meaning","Why it matters"],"rows":[["Invert","Inside bottom of the pipe","Controls gravity flow depth & slope; staked as ''cut to invert''"],["Crown / obvert","Inside top of the pipe","Used for cover/clearance checks, not grade control"],["Slope (grade)","Fall per 100 ft (percent)","Sets self-cleaning velocity; must fall downstream"],["Rim / top","Manhole or inlet surface elevation","Ties structure to finished grade"],["Cover","Ground to top of pipe","Frost/loading protection; checked against minimums"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000004', '1682393e-399c-419e-93a7-1b373316c483', 'text', '{"html":"<h3>Locate before you dig — Texas 811</h3><p>Before any trenching, existing underground utilities must be located. In Texas, the <strong>Underground Facility Damage Prevention and Safety Act (Texas Utilities Code, Chapter 251)</strong> requires an excavator to notify the statewide <strong>one-call notification center by dialing 811</strong> (or submitting an online locate request) a set number of business days before excavating, so that facility operators can mark the location of their buried lines. The construction surveyor frequently supports this process by performing a <strong>utility location / designating survey</strong> &mdash; recording the painted marks and any potholed (exposed) utilities as field-located points &mdash; so the design and stakeout avoid conflicts. Striking an unmarked or mismarked utility can cause injury, outages, and liability, so the locate-and-verify step is both a legal duty and a core safety practice.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000005', '1682393e-399c-419e-93a7-1b373316c483', 'callout', '{"type":"warning","text":"Texas requirement: Under Texas Utilities Code Ch. 251 you must call 811 (Texas811 one-call) and have existing facilities located before excavating. The marks are approximate — hand-dig (pothole) to verify depth and position of critical crossings before machine trenching."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000006', '1682393e-399c-419e-93a7-1b373316c483', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Gravity sewer profile — invert falls at a constant slope from upstream to downstream; stakes give cut to invert."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0004-0000-0000-000000000007', '1682393e-399c-419e-93a7-1b373316c483', 'key_takeaways', '{"title":"Key Takeaways","items":["Stake utilities by offset along an alignment; mark station, offset, and cut to invert.","Gravity systems flow on a designed slope; the invert (not the crown) controls.","Invert at a downstream station = starting invert − slope% × distance/100.","Verify continuous downstream fall and adequate cover before staking.","Texas: call 811 and locate existing utilities (Util. Code Ch. 251) before digging."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000000', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'text', '{"html":"<h3>Slope stakes and the catch point</h3><p>Earthwork shapes the ground from existing topography to the design surface. The key layout point is the <strong>slope stake</strong>, set at the <strong>catch point</strong> (also &lsquo;daylight&rsquo; or &lsquo;hinge of the slope&rsquo;) &mdash; the place where the design side slope intersects natural ground, marking the outer limit of grading. Because that intersection depends on both the design and the existing ground, its position is usually found <strong>iteratively</strong>: the surveyor estimates an offset, checks the ground elevation there, computes where the design slope (e.g., 3:1) would actually catch, and refines until the staked offset matches the computed catch. The slope stake is marked with the <strong>cut or fill</strong> at the catch, the <strong>slope ratio</strong>, and the <strong>offset</strong> back to the reference line or hinge so the operator can build the slope correctly.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000001', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'text', '{"html":"<h3>Grade elevations and cut/fill</h3><p>Computing earthwork stakes rests on two simple relationships. First, the <strong>design grade elevation</strong> at a point on a graded line is the elevation of a known starting point plus the grade times the distance: <em>Elev<sub>design</sub> = Elev<sub>start</sub> + grade% &times; distance &divide; 100</em>. Second, the <strong>cut or fill</strong> at that point is the design elevation minus the existing ground elevation: <em>cut/fill = Elev<sub>design</sub> &minus; Elev<sub>ground</sub></em> &mdash; a negative value means cut (excavate) and a positive value means fill (build up). The surveyor evaluates these at each grade stake, writes &lsquo;C&rsquo; or &lsquo;F&rsquo; with the magnitude, and the operator grades to it. Across a project these point cut/fills also feed the <strong>earthwork volume</strong> estimate (by average-end-area or by comparing the existing and design surfaces), which drives mass-haul and balance decisions.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000002', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'equation', '{"latex":"\\text{Elev}_{design} = \\text{Elev}_{start} + \\frac{g\\% \\cdot d}{100}\\,,\\qquad \\text{cut/fill} = \\text{Elev}_{design} - \\text{Elev}_{ground}","label":"Design grade elevation and cut/fill at a grading stake","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000003', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'text', '{"html":"<h3>Blue tops and fine grading</h3><p>Once rough grading nears the design surface, fine grade is controlled with <strong>blue tops</strong> &mdash; grade stakes (often capped or marked with blue keel/paint) driven down until their <strong>tops sit exactly at the finished subgrade elevation</strong>. Unlike a cut/fill stake, a blue top carries <em>no</em> cut or fill number: the operator simply blades to the top of the stake. Surveyors set blue tops on a grid or along the alignment at intervals tight enough to control the surface (e.g., 25&ndash;50 ft), checking each with the level or total station. Blue tops are the classic final check that subgrade is &lsquo;on grade&rsquo; before base or pavement is placed.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000004', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'text', '{"html":"<h3>Machine control and GPS grading</h3><p>Modern earthmoving increasingly uses <strong>machine control (automated machine guidance, AMG)</strong>, in which a dozer, grader, or excavator carries <strong>GNSS receivers and/or a universal total station (UTS) prism</strong> and an onboard computer comparing the blade&rsquo;s real-time 3D position to a <strong>digital terrain/design model (DTM)</strong>. The machine raises and lowers the blade automatically to hold design grade &mdash; sharply reducing the number of grade stakes needed. The construction surveyor&rsquo;s role shifts but does not disappear: he <strong>builds and verifies the 3D design model</strong>, establishes and maintains the <strong>site control</strong> and base-station/localization that the machines depend on, sets <strong>check shots</strong> to confirm the model and equipment are grading correctly, and provides conventional stakes where machine control is impractical. Good control and a correct model are everything &mdash; an error there is built into the entire site automatically.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000005', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'callout', '{"type":"info","text":"Machine-control reality: GPS/UTS grading is only as good as the site control and the design model behind it. The surveyor''s high-value work moves upstream — accurate control, base localization, a verified DTM — plus independent check shots that catch a bad model before the whole site is graded wrong."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000006', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'table', '{"headers":["Earthwork stake/tool","Controls","Marking / output"],"rows":[["Slope stake","Limit of grading (catch point)","Cut/fill at catch + slope ratio + offset"],["Grade / cut stake","Cut or fill to design at a point","C 2.4 / F 1.1"],["Blue top","Finished subgrade surface","Top of stake = grade (no cut/fill)"],["Machine control (AMG)","Continuous 3D grade","Blade auto-set to DTM; surveyor sets control/checks"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000007', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Grading cross-section — slope stake at the catch point with cut/fill and slope ratio; blue tops control finished subgrade."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0005-0000-0000-000000000008', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'key_takeaways', '{"title":"Key Takeaways","items":["Slope stakes mark the catch point and give cut/fill and the slope ratio there.","Design grade = start elev + grade%·distance/100; cut/fill = design − ground.","Blue tops are driven to finished subgrade — grade to the top, no cut/fill number.","Machine control grades to a 3D model; the surveyor builds/verifies the model and control.","Independent check shots guard against a bad model being graded into the whole site."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0006-0000-0000-000000000000', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'text', '{"html":"<h3>What an as-built survey is</h3><p>An <strong>as-built survey</strong> (also called a <strong>record survey</strong> or, for utilities, a <strong>record drawing</strong>) measures and documents what was <em>actually constructed</em> on the ground, as opposed to what was designed. It is performed <strong>after</strong> all or part of the work is complete &mdash; ideally before backfill for buried items &mdash; and produces a survey/plan showing the real horizontal positions, elevations, and dimensions of the constructed features: building corners, pavements, utilities, structures, and improvements. In effect it is a targeted topographic survey of the new construction, tied to the same control and datum used to lay it out.</p><p>The purpose is twofold: to <strong>verify compliance</strong> with the design (and with permits, setbacks, and easements), and to create a permanent <strong>record</strong> of the constructed condition for operations, maintenance, future design, and dispute resolution. Many of the most valuable as-built data &mdash; pipe inverts, conduit depths, structural tie-ins &mdash; are invisible once the site is finished, so capturing them at the right moment is essential.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0006-0000-0000-000000000001', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'text', '{"html":"<h3>What is measured, and tolerances</h3><p>An as-built records the features that matter for compliance and operation: <strong>building corners and finished-floor elevations</strong>; <strong>pavement and curb lines and grades</strong>; <strong>utility horizontal alignment with invert and rim elevations</strong>, sizes, and materials; <strong>manholes, valves, hydrants, and structures</strong>; and the relationship of improvements to <strong>property lines, setbacks, and easements</strong>. Each measured feature is compared to the design to flag <strong>deviations</strong>. Construction is never perfect, so deviations are judged against the project&rsquo;s <strong>tolerances</strong> &mdash; the allowable departures from design (for example, a few hundredths of a foot on a structural elevation, or a stated horizontal tolerance on a utility). Deviations within tolerance are recorded and accepted; those outside tolerance are flagged for the engineer to evaluate, accept, repair, or formally approve as a design change.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0006-0000-0000-000000000002', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'table', '{"headers":["Feature","As-built data captured","Why recorded"],"rows":[["Building","Corner positions, FFE, footprint","Setback/easement & permit compliance"],["Utilities","Horizontal location, invert & rim, size, material","Hidden once buried; needed for O&M"],["Pavement/grading","Surface grades, curb & flowline elevations","Drainage verification"],["Structures","Tie-ins, top/bottom elevations","Connection & clearance compliance"],["Property relationship","Improvements vs. lines/setbacks/easements","Encroachment & title record"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0006-0000-0000-000000000003', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'text', '{"html":"<h3>As-builts in Texas practice</h3><p>As-built and record surveys serve project <strong>closeout and the permanent record</strong>. Owners, municipalities, and utility districts commonly require record drawings before accepting infrastructure for maintenance, and many Texas jurisdictions require utility and improvement <strong>record data</strong> for acceptance of public improvements. A <strong>record (as-built) survey</strong> that documents the location of improvements relative to boundaries, setbacks, and easements may be sealed by a Registered Professional Land Surveyor (RPLS) and is governed by the TBPELS standards of practice (22 TAC Ch. 138). Accurate as-builts also protect the owner: if a structure is later found to encroach on an easement or a setback, the record survey is the evidence of where things were actually built. As with all sealed surveys, only an RPLS may certify the boundary-related portions of a record survey in Texas.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0006-0000-0000-000000000004', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'callout', '{"type":"warning","text":"Texas note: a record (as-built) survey that depicts improvements relative to property lines, setbacks, or easements is professional surveying — the boundary-related work must be performed/sealed by a Texas RPLS under the Professional Land Surveying Practices Act (Occupations Code Ch. 1071) and TBPELS rules (22 TAC Ch. 138)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0006-0000-0000-000000000005', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: An as-built overlays the constructed work on the design, recording actual positions, inverts, and any deviations."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0006-0000-0000-000000000006', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'key_takeaways', '{"title":"Key Takeaways","items":["An as-built documents what was actually built — position, elevation, dimensions — after construction.","It verifies design/permit/easement compliance and records deviations against tolerances.","Utility as-builts capture invert/rim elevations and buried-line locations before they are hidden.","As-builts support closeout, O&M, future design, and encroachment/title evidence.","Texas: boundary-related record surveys must be sealed by an RPLS under TBPELS rules."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000000', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'text', '{"html":"<h3>Putting the math to work</h3><p>This lesson consolidates the computational core of construction surveying into a set of worked problem types you will see in the field and on exams: <strong>horizontal-curve geometry</strong>, <strong>degree of curve</strong>, <strong>profile-grade elevations</strong>, and <strong>cut/fill at a stake</strong>. Each follows the same disciplined method &mdash; list the knowns, pick the governing formula, check units, compute, and sanity-check the result. The randomized practice problems attached to this module drill exactly these relationships with fresh numbers each time.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000001', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'text', '{"html":"<h3>Worked example 1 — curve tangent and length</h3><p>A simple curve has radius <em>R</em> = 800 ft and intersection angle <em>I</em> = 24&deg;. <strong>Tangent:</strong> T = R&middot;tan(I/2) = 800 &times; tan(12&deg;) = 800 &times; 0.21256 = <strong>170.0 ft</strong>. <strong>Arc length:</strong> L = &pi;RI/180 = &pi; &times; 800 &times; 24 / 180 = <strong>335.1 ft</strong>. So from the PI, the PC is 170.0 ft back along the back tangent and the PT is 170.0 ft along the forward tangent, and the curve is 335.1 ft long along the arc. The total deflection from the back tangent to the PT is I/2 = 12&deg; &mdash; the closing check when staking by deflection angles.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000002', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'text', '{"html":"<h3>Worked example 2 — degree of curve</h3><p>Find the degree of curve (arc definition) for <em>R</em> = 1146 ft: D<sub>a</sub> = 5729.58 / R = 5729.58 / 1146 = <strong>5.00&deg;</strong>. Conversely, a 3&deg; curve has R = 5729.58 / 3 = 1909.9 ft. Remember the inverse relationship: a higher degree of curve is a <em>sharper</em>, tighter curve. This lets a designer specify curves by degree and the surveyor recover the radius needed for layout.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000003', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'text', '{"html":"<h3>Worked example 3 — grade elevation and cut/fill</h3><p>A profile grade starts at station 10+00 with elevation 642.50 ft and runs at +1.80%. <strong>Design elevation at 13+00</strong> (300 ft ahead): Elev = 642.50 + 1.80 &times; 300 / 100 = 642.50 + 5.40 = <strong>647.90 ft</strong>. If the existing ground at 13+00 is 649.30 ft, the <strong>cut/fill</strong> = design &minus; ground = 647.90 &minus; 649.30 = <strong>&minus;1.40 ft</strong> &mdash; a negative value, so the stake is a <strong>cut of 1.40 ft</strong> (excavate 1.4 ft to reach design). Had the ground been 646.50 ft, cut/fill = 647.90 &minus; 646.50 = +1.40 ft, a <strong>fill of 1.40 ft</strong>.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000004', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'equation', '{"latex":"T = R\\tan\\!\\left(\\tfrac{I}{2}\\right),\\;\\; L = \\frac{\\pi R I}{180},\\;\\; D_a = \\frac{5729.58}{R},\\;\\; \\text{cut/fill} = \\text{Elev}_{design}-\\text{Elev}_{ground}","label":"Construction-survey formula summary","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000005', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'callout', '{"type":"info","text":"Unit discipline wins these problems: tan(I/2) takes I/2 in the calculator''s angle mode (use degrees here); L = R·I needs I in radians, so use L = πRI/180 when I is in degrees; and watch the cut/fill sign convention your office uses."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000006', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'table', '{"headers":["Quantity","Formula","Watch out for"],"rows":[["Tangent T","R·tan(I/2)","Use I/2 in degrees"],["Arc length L","πRI/180 (I in deg)","L = R·I only if I in radians"],["Degree of curve Da","5729.58/R","Arc def. (highways), not chord def."],["Grade elevation","start + grade%·dist/100","Sign of grade (rise vs. fall)"],["Cut/fill","design − ground","Negative = cut, positive = fill (confirm convention)"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000007', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A combined layout problem — horizontal curve geometry, profile grade, and cut/fill at a stake."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1810-0007-0000-0000-000000000008', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'key_takeaways', '{"title":"Key Takeaways","items":["T = R·tan(I/2) and L = πRI/180 give the layout geometry of a simple curve.","Degree of curve (arc) Da = 5729.58/R; higher Da means a sharper curve.","Profile elevation = start elevation + grade% × distance/100.","Cut/fill = design − ground; the sign tells the operator to cut or fill.","Method: list knowns, choose the formula, check units (degrees vs. radians), sanity-check."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000001', 'Construction surveying (stakeout)', 'Transferring an engineering design from the plans onto the ground — setting points, lines, and grades for construction. The inverse of topographic/boundary work, which records what exists.', 'Layout, not measurement.', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000002', 'Offset stake', 'A stake set a known horizontal distance to the side of the true line or corner, clear of construction, so the line can be re-established after excavation begins.', 'Off the line so it survives the dig.', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000003', 'Cut vs. fill', 'Cut means the design elevation is below existing ground (excavate); fill means it is above (add material). cut/fill = design elevation − ground elevation.', 'Design minus ground.', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000004', 'Blue top', 'A grade stake driven until its top is exactly at the finished subgrade elevation, so the operator grades to the top of the stake (no cut/fill marking needed).', 'Top = finished subgrade.', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000005', 'Batter board', 'A horizontal board on offset posts outside a building corner, marked at the building line and often set to a grade; strings between opposing boards re-create wall lines and grade over an open excavation.', 'Strings re-create the corner.', 'c1000012-0000-0000-0000-000000000012', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000006', '3-4-5 rule', 'A field method to set or check a right angle using a 3:4:5 (or any multiple) right triangle, derived from the Pythagorean theorem.', 'Pythagorean right-angle check.', 'c1000012-0000-0000-0000-000000000012', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000007', 'Diagonal check', 'Comparing the two diagonals of a rectangular layout; in a true rectangle they are equal, so any difference reveals an out-of-square (racked) layout.', 'Equal diagonals = square.', 'c1000012-0000-0000-0000-000000000012', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000008', 'Finished-floor elevation (FFE)', 'The plan-specified elevation of the building''s finished floor; the controlling vertical datum from which footing, slab, and subgrade elevations are derived.', 'The building''s master elevation.', 'c1000012-0000-0000-0000-000000000012', '08b9b9bd-4eea-48c8-b3f9-072479e48189', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000009', 'PC, PI, PT', 'Point of Curvature (curve begins), Point of Intersection (where the tangents meet), and Point of Tangency (curve ends). The simple curve runs from PC through to PT, with the PI off the curve where the tangents intersect.', 'Begin, intersect, end.', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000010', 'Tangent length T', 'The straight distance from PC to PI (equal to PI to PT) of a simple curve: T = R·tan(I/2), where R is the radius and I the central/intersection angle.', 'R·tan(I/2).', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000011', 'Arc length L', 'The length of the curve along the arc from PC to PT: L = R·I with I in radians, or L = πRI/180 with I in degrees.', 'R·I (radians).', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000012', 'Degree of curve (arc definition)', 'The central angle subtended by a 100-ft arc: Da = 5729.58/R. A larger degree of curve means a sharper, smaller-radius curve. Railroads use the chord definition instead.', '5729.58 ÷ R.', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000013', 'Deflection-angle method', 'Field layout of a circular curve from the PC by turning deflection angles equal to half the subtended central angle; the total deflection from the back tangent to the PT equals I/2.', 'Half the subtended arc angle.', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000014', 'Invert', 'The inside bottom of a pipe. It is the controlling elevation for gravity systems because slope and flow depth are measured from the invert; utility stakes typically give ''cut to invert''.', 'Inside bottom — grade control.', 'c1000012-0000-0000-0000-000000000012', '1682393e-399c-419e-93a7-1b373316c483', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000015', 'Pipe slope (grade)', 'The fall of a gravity pipeline per 100 ft, expressed in percent; it must fall continuously downstream and meet a minimum for self-cleaning velocity.', 'Fall per 100 ft.', 'c1000012-0000-0000-0000-000000000012', '1682393e-399c-419e-93a7-1b373316c483', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000016', 'Downstream invert formula', 'Inv = Inv_start − (slope% × distance / 100). The slope term is subtracted because a gravity line falls in the downstream direction.', 'Start minus fall.', 'c1000012-0000-0000-0000-000000000012', '1682393e-399c-419e-93a7-1b373316c483', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000017', 'Texas 811 / Util. Code Ch. 251', 'Texas''s Underground Facility Damage Prevention and Safety Act requires excavators to call 811 (one-call) and have existing utilities located and marked before excavating.', 'Call before you dig.', 'c1000012-0000-0000-0000-000000000012', '1682393e-399c-419e-93a7-1b373316c483', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000018', 'Slope stake / catch point', 'A stake set where the design side slope intersects natural ground (the catch/daylight/hinge point), marking the grading limit; it gives the cut/fill there, the slope ratio, and the offset.', 'Where the slope meets the ground.', 'c1000012-0000-0000-0000-000000000012', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000019', 'Grade elevation formula', 'Elev_design = Elev_start + grade% × distance / 100. Then cut/fill = design elevation − ground elevation.', 'Start + grade%·d/100.', 'c1000012-0000-0000-0000-000000000012', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000020', 'Blue top', 'A grade stake driven so its top is exactly at finished subgrade; the operator blades to the top of the stake — it carries no cut/fill number.', 'Top is the finished subgrade.', 'c1000012-0000-0000-0000-000000000012', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000021', 'Machine control (AMG)', 'Automated machine guidance: a grader/dozer/excavator with GNSS or UTS positioning and an onboard computer auto-sets the blade to a 3D design model, reducing grade stakes. The surveyor supplies and verifies control and the model.', 'GPS/UTS blade to a 3D model.', 'c1000012-0000-0000-0000-000000000012', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000022', 'As-built (record) survey', 'A survey performed after construction documenting what was actually built — horizontal positions, elevations, and dimensions of constructed features — compared to the design.', 'What was actually built.', 'c1000012-0000-0000-0000-000000000012', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000023', 'As-designed vs. as-built', 'As-designed is the plan; as-built is the measured constructed condition. The comparison reveals deviations, which are judged against project tolerances.', 'Plan vs. reality.', 'c1000012-0000-0000-0000-000000000012', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000024', 'Construction tolerance', 'The allowable departure of constructed work from the design. Deviations within tolerance are accepted and recorded; those outside it are flagged for the engineer.', 'Allowable departure from design.', 'c1000012-0000-0000-0000-000000000012', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000025', 'Utility record drawing', 'An as-built capturing the horizontal location, invert and rim elevations, size, and material of installed utilities — recorded before backfill since the lines become invisible.', 'Capture inverts before backfill.', 'c1000012-0000-0000-0000-000000000012', '85201c11-56a6-4644-a1f9-5e866fb71fc8', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000026', 'Curve layout formulas', 'For a simple curve of radius R and intersection angle I: tangent T = R·tan(I/2); arc length L = πRI/180 (I in degrees); total deflection PC→PT = I/2.', 'T = R·tan(I/2); L = πRI/180.', 'c1000012-0000-0000-0000-000000000012', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000027', 'Degree of curve from radius', 'Da = 5729.58/R (arc definition). Inversely, R = 5729.58/Da. A larger degree of curve is a sharper, smaller-radius curve.', '5729.58 ÷ R.', 'c1000012-0000-0000-0000-000000000012', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000028', 'Profile grade elevation', 'Design elevation at a station = starting elevation + grade% × distance/100. Add for a rising (+) grade, subtract for a falling (−) grade.', 'Start + grade%·d/100.', 'c1000012-0000-0000-0000-000000000012', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1840-0000-0000-0000-000000000029', 'Cut/fill computation', 'cut/fill = design elevation − ground elevation. Negative means cut (excavate); positive means fill (add material) under the common convention.', 'Design minus ground.', 'c1000012-0000-0000-0000-000000000012', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', 'surveying', ARRAY['buildout','module-18']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000001', 'How does construction surveying differ fundamentally from boundary or topographic surveying?', 'multiple_choice', '["It places points, lines, and grades from the design onto the ground (layout)","It only measures existing property corners","It records existing ground for mapping and never sets new points","It is concerned solely with computing parcel area"]'::jsonb, 'It places points, lines, and grades from the design onto the ground (layout)', 'Construction surveying is stakeout/layout — transferring an engineering design onto the ground. Boundary surveying recovers existing lines and topographic surveying records existing ground; both measure what exists, while construction surveying places what will be built.', 'easy', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000002', 'Why are construction stakes commonly set as OFFSET stakes rather than directly on the line?', 'multiple_choice', '["So they survive excavation and the line can be re-established from them","Because offset stakes are cheaper to manufacture","To intentionally hide the true line from the contractor","Because the total station cannot measure points on a line"]'::jsonb, 'So they survive excavation and the line can be re-established from them', 'A stake on the finished line would be destroyed by construction. Offset stakes sit a known distance to the side, clear of the work, so the contractor can re-establish line and grade at any time.', 'easy', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000003', 'A grade stake has a design elevation of 612.4 ft and the existing ground there is 614.0 ft. The stake represents a:', 'multiple_choice', '["Cut of 1.6 ft","Fill of 1.6 ft","Cut of 0.16 ft","Fill of 2.6 ft"]'::jsonb, 'Cut of 1.6 ft', 'cut/fill = design − ground = 612.4 − 614.0 = −1.6 ft. The design is below ground, so material must be excavated: a cut of 1.6 ft.', 'medium', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000004', 'Construction layout should always carry line and grade from a previously set construction stake to the next.', 'true_false', '["True","False"]'::jsonb, 'False', 'Always stake from established control, never from a previously set stake. Stakes get bumped or heaved, and carrying line/grade stake-to-stake propagates error across the project.', 'medium', 'c1000012-0000-0000-0000-000000000012', 'b93d5b7a-89ef-48ac-9881-fb45b9bbde16', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000005', 'What is the fastest field check that a rectangular building layout is square (not racked)?', 'multiple_choice', '["The two diagonals are equal","All four sides are equal","The perimeter matches the plan","The area equals length times width"]'::jsonb, 'The two diagonals are equal', 'In a true rectangle the diagonals are equal, so comparing them instantly reveals an out-of-square layout. Equal sides only proves a parallelogram, and area/perimeter checks do not prove squareness.', 'medium', 'c1000012-0000-0000-0000-000000000012', '08b9b9bd-4eea-48c8-b3f9-072479e48189', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000006', 'What is the primary purpose of batter boards in building layout?', 'multiple_choice', '["To preserve line and grade outside the excavation after the corner stakes are dug out","To support the formwork for the concrete footings","To advertise the contractor''s name on site","To replace the need for any horizontal control"]'::jsonb, 'To preserve line and grade outside the excavation after the corner stakes are dug out', 'Batter boards sit on offset posts outside each corner; strings between opposing boards re-create the building lines (and often grade) over the open excavation once the original corner stakes are destroyed.', 'easy', 'c1000012-0000-0000-0000-000000000012', '08b9b9bd-4eea-48c8-b3f9-072479e48189', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000007', 'Why must a level loop used to set a site benchmark be closed back to the source benchmark?', 'multiple_choice', '["To prove the vertical datum was transferred correctly before building to it","Because the law requires three benchmarks per site","To convert the elevations from feet to meters","Because closing the loop changes the finished-floor elevation"]'::jsonb, 'To prove the vertical datum was transferred correctly before building to it', 'Closing the loop back to the source benchmark proves the elevation transfer. A blown transfer puts the whole building at the wrong height, so the closure check is essential before setting grades.', 'medium', 'c1000012-0000-0000-0000-000000000012', '08b9b9bd-4eea-48c8-b3f9-072479e48189', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000008', 'For a simple horizontal curve, the tangent length T is given by:', 'multiple_choice', '["T = R·tan(I/2)","T = R·sin(I)","T = πRI/180","T = 5729.58/R"]'::jsonb, 'T = R·tan(I/2)', 'The tangent distance from PC to PI is R·tan(I/2). L = πRI/180 is the arc length, and 5729.58/R is the degree of curve — not the tangent.', 'easy', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000009', 'Under the arc definition, a curve with radius R = 1146 ft has a degree of curve of approximately:', 'multiple_choice', '["5°","1°","11.46°","2.5°"]'::jsonb, '5°', 'Da = 5729.58/R = 5729.58/1146 ≈ 5.0°. The degree of curve is the central angle subtended by a 100-ft arc.', 'medium', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000010', 'When staking a simple curve by deflection angles from the PC, the total deflection from the back tangent to the PT equals:', 'multiple_choice', '["I/2","I","2I","90° − I"]'::jsonb, 'I/2', 'The deflection angle to any curve point is half the central angle it subtends, so the total deflection from the PC''s back tangent to the PT is I/2 — a built-in closing check on the layout.', 'medium', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000011', 'A vertical curve joining two grades in profile is normally laid out as a:', 'multiple_choice', '["Equal-tangent parabola","Circular arc of radius R","Straight transition line","Spiral (clothoid)"]'::jsonb, 'Equal-tangent parabola', 'Vertical curves use an equal-tangent parabola because it gives a constant rate of grade change and a smooth ride. Circular arcs and spirals are used for horizontal alignment, not the profile.', 'medium', 'c1000012-0000-0000-0000-000000000012', '6de831fc-aa76-4fe2-9fe4-13e90e2301a6', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000012', 'For a gravity sewer, which elevation controls the design and is referenced by ''cut to invert'' on stakes?', 'multiple_choice', '["The invert (inside bottom of the pipe)","The crown (inside top of the pipe)","The pipe centerline","The finished ground surface"]'::jsonb, 'The invert (inside bottom of the pipe)', 'Gravity flow depth and slope are measured from the invert, so the invert controls and stakes give cut to invert. The crown is used for cover/clearance, not grade control.', 'easy', 'c1000012-0000-0000-0000-000000000012', '1682393e-399c-419e-93a7-1b373316c483', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000013', 'A sewer''s upstream invert is 521.00 ft and the line falls at 0.50% to a manhole 200 ft downstream. The downstream invert is:', 'multiple_choice', '["520.00 ft","522.00 ft","521.50 ft","519.00 ft"]'::jsonb, '520.00 ft', 'Inv = 521.00 − (0.50 × 200 / 100) = 521.00 − 1.00 = 520.00 ft. The slope term is subtracted because the gravity line falls downstream.', 'medium', 'c1000012-0000-0000-0000-000000000012', '1682393e-399c-419e-93a7-1b373316c483', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000014', 'Under Texas law, what must an excavator do before trenching to protect existing underground utilities?', 'multiple_choice', '["Call 811 (one-call) so facility operators locate and mark their lines (Util. Code Ch. 251)","Nothing, as long as a surveyor is present","Excavate first and report any struck lines afterward","Obtain a boundary survey of the entire county"]'::jsonb, 'Call 811 (one-call) so facility operators locate and mark their lines (Util. Code Ch. 251)', 'The Texas Underground Facility Damage Prevention and Safety Act (Util. Code Ch. 251) requires notifying the one-call center (811) before excavating so operators can mark buried facilities. The marks should then be verified by potholing.', 'easy', 'c1000012-0000-0000-0000-000000000012', '1682393e-399c-419e-93a7-1b373316c483', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000015', 'A slope stake is set at the ''catch point.'' What does the catch point mark?', 'multiple_choice', '["Where the design side slope intersects natural ground (the grading limit)","The centerline of the roadway","The exact finished subgrade surface","The location of the nearest benchmark"]'::jsonb, 'Where the design side slope intersects natural ground (the grading limit)', 'The catch (daylight/hinge) point is where the design slope meets existing ground, marking the outer limit of grading. The slope stake there gives the cut/fill, slope ratio, and offset.', 'medium', 'c1000012-0000-0000-0000-000000000012', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000016', 'What distinguishes a blue top from an ordinary cut/fill grade stake?', 'multiple_choice', '["Its top is driven exactly to finished subgrade, so it carries no cut/fill number","It is always set on the centerline only","It marks horizontal line but never elevation","It is read only by GPS machine control"]'::jsonb, 'Its top is driven exactly to finished subgrade, so it carries no cut/fill number', 'A blue top is driven until its top is at finished subgrade; the operator blades to the top of the stake. Because the grade IS the top of the stake, no cut or fill is marked.', 'medium', 'c1000012-0000-0000-0000-000000000012', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000017', 'In machine-control (GPS/UTS) grading, what is the surveyor''s most critical contribution?', 'multiple_choice', '["Establishing/verifying accurate site control and a correct 3D design model, plus check shots","Operating the dozer blade manually at all times","Eliminating the need for any benchmarks or control","Setting a cut/fill stake every two feet across the site"]'::jsonb, 'Establishing/verifying accurate site control and a correct 3D design model, plus check shots', 'Machine control grades to a 3D model from site control and localization; an error there is built into the whole site. The surveyor''s high-value work is accurate control, a verified model, and independent check shots.', 'medium', 'c1000012-0000-0000-0000-000000000012', '47a67367-9553-4fd4-b1cb-8d96d58dacfb', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000018', 'What is the primary purpose of an as-built (record) survey?', 'multiple_choice', '["To document what was actually constructed and compare it to the design","To set out the building corners before construction","To compute the volume of concrete to be ordered","To establish new property boundaries for subdivision"]'::jsonb, 'To document what was actually constructed and compare it to the design', 'An as-built records the actual constructed positions, elevations, and dimensions after construction and compares them to the design to verify compliance and create a permanent record. Setting corners beforehand is stakeout, not an as-built.', 'easy', 'c1000012-0000-0000-0000-000000000012', '85201c11-56a6-4644-a1f9-5e866fb71fc8', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000019', 'Why is it important to capture utility as-built data before backfill?', 'multiple_choice', '["Inverts and buried-line locations become invisible once covered, yet are needed for the permanent record","Backfill changes the pipe material","The contractor is paid only for buried pipe","Inverts are irrelevant after construction"]'::jsonb, 'Inverts and buried-line locations become invisible once covered, yet are needed for the permanent record', 'Once buried, a utility''s invert/rim elevations and horizontal location cannot be measured directly. Capturing them before backfill preserves the record needed for operations, maintenance, and future design.', 'medium', 'c1000012-0000-0000-0000-000000000012', '85201c11-56a6-4644-a1f9-5e866fb71fc8', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000020', 'A measured as-built deviation that exceeds the project''s stated tolerance should be:', 'multiple_choice', '["Flagged for the engineer to evaluate, accept, repair, or approve as a change","Quietly erased from the record so the project passes","Always rebuilt regardless of engineering review","Ignored because no construction is perfect"]'::jsonb, 'Flagged for the engineer to evaluate, accept, repair, or approve as a change', 'Deviations within tolerance are recorded and accepted; those outside tolerance are flagged for the engineer to evaluate and decide how to resolve. Erasing or ignoring them defeats the purpose of the record survey.', 'medium', 'c1000012-0000-0000-0000-000000000012', '85201c11-56a6-4644-a1f9-5e866fb71fc8', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000021', 'A simple curve has R = 500 ft and I = 30°. What is the tangent length T (to the nearest 0.1 ft)?', 'numeric_input', '[]'::jsonb, '134.0', 'T = R·tan(I/2) = 500 × tan(15°) = 500 × 0.267949 = 134.0 ft.', 'medium', 'c1000012-0000-0000-0000-000000000012', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000022', 'A profile grade of +1.50% starts at elevation 700.00 ft. What is the design elevation 240 ft ahead?', 'numeric_input', '[]'::jsonb, '703.60', 'Elev = 700.00 + 1.50 × 240 / 100 = 700.00 + 3.60 = 703.60 ft.', 'easy', 'c1000012-0000-0000-0000-000000000012', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1830-0000-0000-0000-000000000023', 'Using the arc definition, the degree of curve increases as the radius of the curve decreases (sharper curve).', 'true_false', '["True","False"]'::jsonb, 'True', 'Da = 5729.58/R, an inverse relationship: as R decreases the degree of curve increases, meaning a sharper, tighter curve.', 'easy', 'c1000012-0000-0000-0000-000000000012', '2eb63ef7-f13a-44cc-8ae4-943f5a44ede3', ARRAY['buildout','module-18']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
