INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1860-0000-0000-0000-000000000001', 'A simple horizontal curve has a radius R = {{R}} ft and an intersection (central) angle I = {{I}}°. What is the tangent length T (ft) from the PC to the PI?', 'numeric_input', '[]'::jsonb, '0', 'The tangent distance from the PC to the PI of a simple curve is T = R·tan(I/2) = {{R}} × tan({{I}}°/2) = {{_answer}} ft.', 'medium', 'c1000012-0000-0000-0000-000000000012', NULL, ARRAY['buildout','module-18','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1850-0000-0000-0000-000000000001', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1860-0000-0000-0000-000000000002', 'A simple horizontal curve has a radius R = {{R}} ft and an intersection (central) angle I = {{I}}°. What is the arc length L (ft) of the curve from the PC to the PT?', 'numeric_input', '[]'::jsonb, '0', 'Arc length is L = R·I with I in radians, i.e. L = πRI/180 = π × {{R}} × {{I}} ÷ 180 = {{_answer}} ft.', 'medium', 'c1000012-0000-0000-0000-000000000012', NULL, ARRAY['buildout','module-18','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1850-0000-0000-0000-000000000002', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1860-0000-0000-0000-000000000003', 'A profile grade starts at elevation {{startElev:f2}} ft and runs at a constant grade of {{grade:f2}}%. What is the design elevation (ft) at a point {{dist}} ft ahead along the grade?', 'numeric_input', '[]'::jsonb, '0', 'Along a tangent grade the elevation is start + grade%·distance/100 = {{startElev:f2}} + {{grade:f2}}×{{dist}}/100 = {{_answer}} ft.', 'easy', 'c1000012-0000-0000-0000-000000000012', NULL, ARRAY['buildout','module-18','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1850-0000-0000-0000-000000000003', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1860-0000-0000-0000-000000000004', 'At a grade stake the design elevation is {{designElev:f2}} ft and the existing ground elevation is {{groundElev:f2}} ft. What is the cut/fill (ft), where a negative value is a cut and a positive value is a fill?', 'numeric_input', '[]'::jsonb, '0', 'Cut/fill = design − ground = {{designElev:f2}} − {{groundElev:f2}} = {{_answer}} ft. A negative result is a cut (excavate); a positive result is a fill (add material).', 'easy', 'c1000012-0000-0000-0000-000000000012', NULL, ARRAY['buildout','module-18','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1850-0000-0000-0000-000000000004', 0.02);
