UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Construction surveying translates the design (plans) onto the ground — it is layout, not measurement of what exists','Everything is staked from established horizontal and vertical control, never from prior stakes','Offset stakes are set a known horizontal distance off the line so they survive excavation','Cut = design below ground (excavate); Fill = design above ground (add material): cut/fill = design − ground']::text[], learning_objectives=ARRAY['Distinguish construction surveying (stakeout) from boundary and topographic surveying','Explain the role of horizontal and vertical control in setting out a project','Read and set offset, cut, and grade stakes and interpret stake markings','Define cut and fill and compute a stake''s cut/fill from design and ground elevations']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='b93d5b7a-89ef-48ac-9881-fb45b9bbde16';
DELETE FROM lesson_blocks WHERE lesson_id='b93d5b7a-89ef-48ac-9881-fb45b9bbde16';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Building layout starts from a control network and an established baseline, not from existing structures','Square corners by the 3-4-5 (Pythagorean) rule and check by comparing the two diagonals','Batter boards held offset from each corner preserve line and grade after the corner stakes are dug out','A site benchmark transfers the vertical datum so finished-floor and footing elevations are correct']::text[], learning_objectives=ARRAY['Establish a primary control network and a building baseline for layout','Lay out building corners and lines by coordinates and verify with diagonals (3-4-5)','Set and use batter boards and offset hubs to preserve line and grade during excavation','Transfer a vertical datum (benchmark) to the site and set finished-floor elevation']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='08b9b9bd-4eea-48c8-b3f9-072479e48189';
DELETE FROM lesson_blocks WHERE lesson_id='08b9b9bd-4eea-48c8-b3f9-072479e48189';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['A simple curve is defined by radius R and intersection (central) angle I; tangent T = R·tan(I/2)','Arc length L = R·I (I in radians) = R·I·π/180 (I in degrees); the curve runs PC → PT through PI','Degree of curve (arc) Da = 5729.58/R; larger Da means a sharper (smaller-radius) curve','Curves are staked by deflection angles from the PC; vertical curves are parabolas joining grades']::text[], learning_objectives=ARRAY['Define the elements of a simple horizontal curve: R, I (Δ), T, L, and the PC/PI/PT','Relate radius and degree of curve (arc definition) and compute tangent and curve length','Lay out a horizontal curve by deflection angles from the PC','Describe vertical curves and compute grade elevations along a profile']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='6de831fc-aa76-4fe2-9fe4-13e90e2301a6';
DELETE FROM lesson_blocks WHERE lesson_id='6de831fc-aa76-4fe2-9fe4-13e90e2301a6';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Utilities are staked by offset along an alignment, with cut to the pipe invert at each station','Gravity systems (sewer, storm) flow on a designed slope; the invert elevation controls','Invert elevation at a station = upstream invert − slope × distance (downstream falls)','Texas law (Util. Code Ch. 251) requires calling 811 before digging to locate existing lines']::text[], learning_objectives=ARRAY['Stake the horizontal alignment and offset for a gravity or pressure pipeline','Compute pipe invert elevations along a designed grade and the cut to invert at a station','Explain gravity-flow grade requirements and why invert (not pipe crown) controls','Apply Texas one-call (811) requirements to locate existing utilities before excavation']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='1682393e-399c-419e-93a7-1b373316c483';
DELETE FROM lesson_blocks WHERE lesson_id='1682393e-399c-419e-93a7-1b373316c483';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A slope stake marks the catch point — where the design slope meets natural ground — with cut/fill and slope ratio there','Grade elevation along a line = start elevation + grade% × distance/100; cut/fill = design − ground','Blue tops are driven so their tops are exactly at finished subgrade, controlling fine grading','Machine control (GPS/UTS grading) uses a 3D design model; the surveyor builds/checks the model and control']::text[], learning_objectives=ARRAY['Set slope stakes at the catch point and read slope-stake markings (cut/fill and ratio)','Compute design grade elevations and the cut or fill at a grading stake','Set blue tops to finished subgrade and explain their role in fine grading','Describe machine control (GPS/total-station grading) and the surveyor''s supporting role']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='47a67367-9553-4fd4-b1cb-8d96d58dacfb';
DELETE FROM lesson_blocks WHERE lesson_id='47a67367-9553-4fd4-b1cb-8d96d58dacfb';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['An as-built (record) survey documents what was actually built — position, elevation, and dimensions — after construction','It compares the constructed work to the design to verify compliance and record deviations','Utility as-builts capture invert/rim elevations and horizontal location of buried lines for the permanent record','As-builts support project closeout, future maintenance, easement verification, and recordkeeping']::text[], learning_objectives=ARRAY['Define an as-built (record) survey and explain its purpose and timing','Identify what is measured on an as-built and how it is documented','Compare as-designed vs. as-built and assess construction tolerances and deviations','Recognize the role of as-builts for utilities, easements, and Texas record/permit closeout']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='85201c11-56a6-4644-a1f9-5e866fb71fc8';
DELETE FROM lesson_blocks WHERE lesson_id='85201c11-56a6-4644-a1f9-5e866fb71fc8';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Curve layout reduces to a few formulas: T = R·tan(I/2), L = πRI/180, Da = 5729.58/R','Profile grades give elevation = start + grade%·distance/100 along a tangent','Cut/fill = design − ground; sign tells the operator to excavate (cut) or build up (fill)','Set up each problem by identifying knowns, choosing the right formula, and watching units (degrees vs. radians)']::text[], learning_objectives=ARRAY['Compute the tangent length and arc length of a simple horizontal curve from R and I','Determine the degree of curve (arc definition) for a given radius','Calculate design grade elevations along a profile from a starting elevation and percent grade','Solve cut/fill at a grade stake from design and ground elevations and choose correct sign']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='2eb63ef7-f13a-44cc-8ae4-943f5a44ede3';
DELETE FROM lesson_blocks WHERE lesson_id='2eb63ef7-f13a-44cc-8ae4-943f5a44ede3';
  'eeee1850-0000-0000-0000-000000000001', 'Tangent length of a simple horizontal curve', 'Compute the tangent distance T of a simple circular curve from its radius and intersection angle.', 'Construction Surveying — Horizontal Curves', 'Tangent length', 'numeric_input', 'medium', 'A simple horizontal curve has a radius R = {{R}} ft and an intersection (central) angle I = {{I}}°. What is the tangent length T (ft) from the PC to the PI?', 'R*tan(toRad(I/2))', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"integer","min":400,"max":1500},{"name":"I","type":"integer","min":10,"max":60}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Half the central angle","formula":"I ÷ 2","calculation_template":"{{I}}° ÷ 2"},{"step_number":2,"title":"Tangent length","result_template":"T = {{R}} × tan({{I}}°/2) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The tangent distance from the PC to the PI of a simple curve is T = R·tan(I/2) = {{R}} × tan({{I}}°/2) = {{_answer}} ft.', 'c1000012-0000-0000-0000-000000000012', ARRAY['buildout','module-18','practice']::text[], true, 'buildout:m18');
  'eeee1850-0000-0000-0000-000000000002', 'Arc length of a simple horizontal curve', 'Compute the arc (curve) length L of a simple circular curve from its radius and intersection angle.', 'Construction Surveying — Horizontal Curves', 'Arc length', 'numeric_input', 'medium', 'A simple horizontal curve has a radius R = {{R}} ft and an intersection (central) angle I = {{I}}°. What is the arc length L (ft) of the curve from the PC to the PT?', 'R*I*PI/180', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"integer","min":400,"max":1500},{"name":"I","type":"integer","min":10,"max":60}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Convert I to radians","formula":"I × π ÷ 180","calculation_template":"{{I}}° × π ÷ 180"},{"step_number":2,"title":"Arc length","result_template":"L = {{R}} × {{I}}° × π ÷ 180 = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Arc length is L = R·I with I in radians, i.e. L = πRI/180 = π × {{R}} × {{I}} ÷ 180 = {{_answer}} ft.', 'c1000012-0000-0000-0000-000000000012', ARRAY['buildout','module-18','practice']::text[], true, 'buildout:m18');
  'eeee1850-0000-0000-0000-000000000003', 'Profile grade elevation along a tangent', 'Compute the design elevation at a station from a starting elevation, percent grade, and distance.', 'Construction Surveying — Grade & Slope', 'Profile grade', 'numeric_input', 'easy', 'A profile grade starts at elevation {{startElev:f2}} ft and runs at a constant grade of {{grade:f2}}%. What is the design elevation (ft) at a point {{dist}} ft ahead along the grade?', 'startElev + grade*dist/100', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"startElev","type":"float","min":500,"max":800,"decimals":2},{"name":"grade","type":"float","min":-4,"max":4,"decimals":2},{"name":"dist","type":"integer","min":100,"max":500}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Rise over the run","formula":"grade% × distance ÷ 100","calculation_template":"{{grade:f2}}% × {{dist}} ÷ 100"},{"step_number":2,"title":"Design elevation","result_template":"{{startElev:f2}} + ({{grade:f2}}% × {{dist}} ÷ 100) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Along a tangent grade the elevation is start + grade%·distance/100 = {{startElev:f2}} + {{grade:f2}}×{{dist}}/100 = {{_answer}} ft.', 'c1000012-0000-0000-0000-000000000012', ARRAY['buildout','module-18','practice']::text[], true, 'buildout:m18');
  'eeee1850-0000-0000-0000-000000000004', 'Cut or fill at a grade stake', 'Compute the signed cut/fill at a stake from the design and existing-ground elevations.', 'Construction Surveying — Earthwork', 'Cut/fill', 'numeric_input', 'easy', 'At a grade stake the design elevation is {{designElev:f2}} ft and the existing ground elevation is {{groundElev:f2}} ft. What is the cut/fill (ft), where a negative value is a cut and a positive value is a fill?', 'designElev - groundElev', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"designElev","type":"float","min":600,"max":700,"decimals":2},{"name":"offset","type":"float","min":-4,"max":4,"decimals":2}]'::jsonb, '[{"name":"groundElev","formula":"round(designElev - offset,2)"}]'::jsonb, '[{"step_number":1,"title":"Subtract ground from design","formula":"design − ground","calculation_template":"{{designElev:f2}} − {{groundElev:f2}}"},{"step_number":2,"title":"Cut/fill","result_template":"= {{_answer}} ft (negative = cut, positive = fill)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Cut/fill = design − ground = {{designElev:f2}} − {{groundElev:f2}} = {{_answer}} ft. A negative result is a cut (excavate); a positive result is a fill (add material).', 'c1000012-0000-0000-0000-000000000012', ARRAY['buildout','module-18','practice']::text[], true, 'buildout:m18');
COMMIT;
SELECT 'm18 Construction Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000012-0000-0000-0000-000000000012') || ' blocks.' AS status;